/* Natives <input> steuert die dokumentierte Optik über Pseudoklassen —
   die Modifier-Klassen (.z-checkbox--*) werden hier NICHT gesetzt. */
.checkbox-field {
  display: inline-flex;
  align-items: center;
  gap: var(--z-ds-space-8);
  cursor: pointer;
}

/* Natives Steuerelement visuell verstecken, aber fokussier- und bedienbar lassen. */
.checkbox-native {
  position: absolute;
  width: 16px;
  height: 16px;
  margin: 0;
  opacity: 0;
}

/* Hover wie .z-checkbox--hover. */
.checkbox-native:hover ~ .z-checkbox {
  background-color: var(--z-ds-color-background-10);
}

/* Tastaturfokus wie .z-checkbox--focus: 2px-Rahmen in Focus-100. */
.checkbox-native:focus-visible ~ .z-checkbox {
  border: 2px solid var(--z-ds-color-focus-100);
}

/* Checked wie .z-checkbox--checked: dunkle Füllung, Haken sichtbar. */
.checkbox-native:checked ~ .z-checkbox {
  background-color: var(--z-ds-color-text-100);
  border-color: var(--z-ds-color-text-100);
}
.checkbox-native:checked ~ .z-checkbox .z-checkbox__check {
  display: block;
}

/* Disabled wie .z-checkbox--disabled. */
.checkbox-native:disabled ~ .z-checkbox {
  border-color: var(--z-ds-color-border-70);
}
.checkbox-native:checked:disabled ~ .z-checkbox {
  background-color: var(--z-ds-color-text-40);
  border-color: var(--z-ds-color-text-40);
}
